INSERT INTO _dytopia_public_catalog_recipes ("Id", "DietitianId", "Name", "Slug", "Description", "IsPublic", "IsDemo", "IsDraft", "IsHiddenFromProduction", "IsArchived", "ArchivedAtUtc", "StepsJson", "TagsJson", "PrepTimeMinutes", "CookTimeMinutes", "Servings", "CaloriesKcal", "ProteinGrams", "CarbsGrams", "FatGrams") VALUES
('24319c96-5fd3-5286-a0c7-468b7410be91'::uuid, NULL, 'Tarçınlı kivili yulaf ve süzme yoğurt kasesi', 'tarcinli-kivili-yulaf-ve-suzme-yogurt-kasesi-24319c', 'Akdeniz esintili bu kahvaltı, lif ve sağlıklı yağ dengesi için tasarlandı. Kivi, yulaf ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile kivi parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce yulaf tabanını, üzerine süzme yoğurt karışımını alın.", "Ceviz ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "akdeniz", "fermente", "c vitamini"]', 8, 4, 1, 506, 25.00, 51.00, 22.40),
('a88700b2-2844-503a-b6eb-b0ba268f9c85'::uuid, NULL, 'Kekikli bezelyeli ve mantarlı omlet', 'kekikli-bezelyeli-ve-mantarli-omlet-a88700', 'Tok tutan dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Bezelye ve mantar küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp lor peyniri ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "yüksek protein", "tava", "lif"]', 11, 11, 1, 515, 46.00, 25.00, 25.70),
('5e400897-d136-5abf-9b78-0d24a0440715'::uuid, NULL, 'Elmalı armutlu ve havuçlu smoothie', 'elmali-armutlu-ve-havuclu-smoothie-5e4008', 'Pratik hazırlanabilen ara öğün alternatifi olan bu smoothie, gün içinde sürdürülebilir enerji hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Elma ve armut meyvelerini uygun boyutta hazırlayın.", "Blender haznesine lor peyniri, havuç ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "pratik", "lif", "renkli sebze"]', 9, 0, 1, 378, 21.70, 49.00, 10.60),
('7169eb4e-d5a7-5fd3-8ecc-dcee16a81ac3'::uuid, NULL, 'Zencefilli fasulyeli kerevizli çorbası', 'zencefilli-fasulyeli-kerevizli-corbasi-7169eb', 'Hafif yapılı bu çorba, baklagil bazlı yapısıyla mikrobesin çeşitliliği ve sindirim konforu sunar. Öğle ya da akşam öğününde hafif ama doyurucu bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kereviz ve temel aromatik sebzeleri küçük küpler halinde doğrayın.", "Tencerede kısa süre kavurup baklagili ekleyin.", "Üzerini geçecek kadar sıcak su ilave edip kısık ateşte pişirin.", "Zencefilli dokunuşunu ekleyip kıvamı oturana kadar kaynatın.", "İsterseniz kısmen blenderdan geçirip sıcak servis edin."]', '["çorba", "öğle yemeği", "sebze ağırlıklı", "baklagil", "lif", "hafif"]', 18, 23, 3, 364, 16.00, 47.00, 12.40),
('f2572c37-7040-53bb-b197-f7bbdf3f1e46'::uuid, NULL, 'Fesleğenli levrekli kinoa salata kasesi', 'feslegenli-levrekli-kinoa-salata-kasesi-f2572c', 'Dengeli porsiyonlu bu kase, levrek fileto ve kinoa ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kinoa tabanını ayrı bir kapta haşlayıp süzün.", "Levrek Fileto için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Pancar ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "denge", "balık", "kompleks karbonhidrat", "fesleğenli"]', 11, 21, 1, 501, 32.00, 41.00, 23.20),
('5c34192f-a9e4-5495-b8c7-1342ffb3da9a'::uuid, NULL, 'Yoğurt soslu hindili biberli wrap', 'yogurt-soslu-hindili-biberli-wrap-5c3419', 'Kolay taşınabilir öğün düzeni hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Hindi Göğsü harcını önceden pişirip ılıtın.", "Renkli Biber ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine yoğurt sos sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "ofis dostu", "yüksek protein", "hafif", "taşınabilir"]', 11, 15, 1, 432, 38.00, 40.00, 13.30),
('0fe65f8e-d6ca-5866-84c7-fbb24f5512b1'::uuid, NULL, 'Limonlu levrekli semizotlu fırın tepsisi', 'limonlu-levrekli-semizotlu-firin-tepsisi-0fe65f', 'Ferah ve renkli ve dengeli bu ana öğün, tek tepside pratik hazırlık sunar. Levrek Fileto ile semizotu uyumu hafif akşam yemekleri için güçlü bir seçenektir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Fırını önceden 190 dereceye ısıtın.", "Levrek Fileto ve sebzeleri eşit pişecek boyutta hazırlayın.", "Malzemeleri tepsiye yayıp zeytinyağı ve baharatlarla harmanlayın.", "Limonlu dokunuşuyla lezzeti tamamlayın.", "Kızarana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "fırın", "akdeniz", "balık", "omega-3", "limonlu"]', 14, 21, 2, 372, 30.00, 16.00, 20.90),
('9d9c5259-4cda-5f6c-b285-30e15cda2785'::uuid, NULL, 'Tavuklu karabuğdaylı dolgulu patlıcan', 'tavuklu-karabugdayli-dolgulu-patlican-9d9c52', 'Yüksek protein odaklı bu fırın yemeği, porsiyon kontrolünü kolaylaştıran düzenli bir ana öğündür. Patlıcan içinde hazırlanan iç harç, kas korunumu ve uzun süreli tokluk desteği sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Patlıcan içini hazırlayıp dolguluk hale getirin.", "Tavuk Göğsü ve karabuğday bazlı iç harcı tavada kısa süre çevirin.", "Fesleğenli baharatlarını ekleyip iç harcı dengeleyin.", "Sebzelerin içine paylaştırıp fırın kabına dizin.", "Yumuşayana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "dolma", "yüksek protein", "glutensiz", "fırın"]', 15, 24, 2, 450, 35.00, 45.00, 14.50),
('fec1152c-66f2-5667-aa38-fd4d45003b2c'::uuid, NULL, 'Kabaklı tavuklu mini köfte', 'kabakli-tavuklu-mini-kofte-fec115', 'Hızlı hazırlanabilen bu tarif, kontrollü porsiyonda hazırlanabilen çok yönlü bir tabak sunar. Yanına eklenen sos ile ara öğün ya da ana öğün olarak değerlendirilebilir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tavuk Göğsü bazını robotta çekip kabak ile karıştırın.", "Baharatları ekleyip şekil alacak kıvama getirin.", "Karışımdan küçük parçalar alıp köfte formu verin.", "Tavada ya da fırında kontrollü şekilde pişirin.", "Humus ile birlikte servis edin."]', '["pratik", "köfte", "yüksek protein", "sebze", "yüksek tokluk"]', 13, 17, 3, 576, 52.00, 24.00, 30.20),
('09d1acc5-8e41-55f6-9376-c5eadceaf972'::uuid, NULL, 'Kekikli tavuklu sebze sote', 'kekikli-tavuklu-sebze-sote-09d1ac', 'Sebze ağırlıklı bu tava yemeği, tek kapta pişen düzenli bir öğün sunar. Tavuk Göğsü ve sebzelerin diri dokusu sayesinde hafif ama tatmin edicidir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tavuk Göğsü uygun boyutta hazırlayın.", "Ispanak ve patlıcan sebzelerini benzer büyüklükte doğrayın.", "Wok ya da geniş tavayı iyice ısıtıp malzemeleri sırasıyla ekleyin.", "Kekikli aroması ile son dokunuşu yapın.", "Sebzeler hafif diri kalacak şekilde servis edin."]', '["ana öğün", "sote", "sebze ağırlıklı", "yüksek protein", "demir kaynağı", "tek tava"]', 13, 16, 2, 363, 31.00, 20.00, 17.70),
('e677db0b-bff6-5e04-814f-a9fcf260f460'::uuid, NULL, 'Sumaklı ton balıklı bulgur pilavı', 'sumakli-ton-balikli-bulgur-pilavi-e677db', 'Ölçülü yapılı bu pilav tabağı, gün içi enerji ihtiyacını kontrollü karşılamak için tasarlandı. Tane tane doku ve dengeli protein miktarıyla günlük planlara kolayca uyum sağlar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Bulgur tabanını yıkayıp uygun kıvamda pişirin.", "Ton Balığı ve karnabahar ile ayrı bir iç harç hazırlayın.", "Pişen tahılı harçla birleştirip birkaç dakika dinlendirin.", "Sumaklı ile aromayı canlandırın.", "Ana öğün olarak sıcak servis edin."]', '["öğle yemeği", "pilav", "denge", "lif", "balık", "sumaklı"]', 15, 23, 3, 497, 30.00, 37.00, 25.40),
('64919b9e-07ea-5b3c-af72-d38163dac4be'::uuid, NULL, 'Ton balıklı brokolili kabak spagetti', 'ton-balikli-brokolili-kabak-spagetti-64919b', 'Ofis temposuna uygun bu tabak, klasik makarna hissini daha kontrollü bir içerikle sunar. Sos ve sebze dengesi sayesinde hafif ama tatmin edici bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak Spagetti tabanını uygun süre boyunca pişirin.", "Ton Balığı ve brokoli ile sos temelini hazırlayın.", "Domates Sosu karışımını tavada kısa süre çevirin.", "Haşlanan tabanı sos ile buluşturup birkaç dakika dinlendirin.", "Sıcak servis edip taze otlarla tamamlayın."]', '["akşam yemeği", "makarna", "ofis dostu", "balık", "düşük karbonhidrat", "fesleğenli"]', 10, 15, 2, 336, 30.00, 26.00, 12.50),
('16cbca3f-2e1a-5e38-9209-bb51da03082d'::uuid, NULL, 'Çilekli yulaf puding', 'cilekli-yulaf-puding-16cbca', 'Ferah ve renkli ara öğün olarak hazırlanan bu puding, kontrollü tatlı isteği için iyi bir alternatiftir. Protein ve lif desteğiyle gereksiz atıştırmayı azaltmaya yardımcı olur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını sıvı bileşenle karıştırıp dinlenmeye bırakın.", "Lor Peyniri ile yumuşak bir kıvam hazırlayın.", "Çilek dilimleri ve tabanı katmanlı şekilde birleştirin.", "Hindistan Cevizi ile dokusal kontrast ekleyin.", "Soğutup servis edin."]', '["ara öğün", "puding", "akdeniz", "kahvaltı", "meyveli", "tatlı ihtiyacına çözüm"]', 10, 0, 1, 457, 27.00, 46.00, 18.30),
('a8595261-3daa-541e-8010-f95e70d9c363'::uuid, NULL, 'Avokadolu mercimekli sandviç', 'avokadolu-mercimekli-sandvic-a85952', 'Yüksek protein odaklı bu sandviç, dışarıda yemek gereken günlerde planı korumayı kolaylaştırır. Tam Buğday Ekmeği tabanı ve dengeli iç harcı sayesinde hızlı ama doyurucu bir seçenek sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Ekmeği dilimlerini hafifçe ısıtın.", "Yüzeye önce avokado ezmesi, ardından yeşil mercimek katmanını ekleyin.", "Kabak ile taze bir katman oluşturun.", "Sandviçi sıkı şekilde kapatıp ikiye bölün.", "İsteğe göre yanında ayran veya salata ile servis edin."]', '["öğle yemeği", "sandviç", "yüksek protein", "baklagil", "taşınabilir"]', 11, 5, 1, 489, 24.00, 64.00, 15.20),
('decf6dec-a72c-536a-9c7c-488835670110'::uuid, NULL, 'Sumaklı hindili ana tabak', 'sumakli-hindili-ana-tabak-decf6d', 'Hızlı hazırlanabilen bu tarif, akşam öğününde daha düzenli bir tabak kurmak isteyenler için hazırlandı. Hindi Göğsü ile karabuğday eşleşmesi dengeli makro dağılımı sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Hindi Göğsü ana malzemesini tercih ettiğiniz yöntemle pişirin.", "Karabuğday garnitürünü ayrı kapta hazırlayın.", "Semizotu eşlikçisini diri kalacak şekilde pişirin.", "Tüm parçaları tabakta dengeli porsiyonla birleştirin.", "Servis öncesi son baharat dokunuşunu ekleyin."]', '["akşam yemeği", "ana tabak", "pratik", "yüksek protein", "glutensiz", "sumaklı"]', 16, 16, 1, 501, 34.00, 34.00, 25.40),
('4c99580c-cabe-5ec7-9629-e53fbf1013c0'::uuid, NULL, 'Tarçınlı şeftalili yulaf ve lor peyniri kasesi', 'tarcinli-seftalili-yulaf-ve-lor-peyniri-kasesi-4c9958', 'Sebze ağırlıklı bu kahvaltı, mikrobesin çeşitliliği ve sindirim konforu için tasarlandı. Şeftali, yulaf ve lor peyniri birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Lor Peyniri ile şeftali parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce yulaf tabanını, üzerine lor peyniri karışımını alın.", "Keten Tohumu ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "sebze ağırlıklı", "protein", "yaz meyvesi"]', 11, 3, 1, 464, 28.00, 49.00, 17.30),
