('f0da852e-0b6c-59b8-8cd6-fa2688e5d1f6'::uuid, NULL, 'Vanilyalı şeftalili yulaf ve süzme yoğurt kasesi', 'vanilyali-seftalili-yulaf-ve-suzme-yogurt-kasesi-f0da85', 'Sebze ağırlıklı bu kahvaltı, mikrobesin çeşitliliği ve sindirim konforu için tasarlandı. Şeftali, yulaf ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile şeftali parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce yulaf tabanını, üzerine süzme yoğurt karışımını alın.", "Ceviz ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "sebze ağırlıklı", "fermente", "yaz meyvesi"]', 13, 3, 1, 513, 25.00, 53.00, 22.30),
('69da1eed-8620-576b-a3fb-170eec9973d4'::uuid, NULL, 'Naneli semizotlu ve brokolili omlet', 'naneli-semizotlu-ve-brokolili-omlet-69da1e', 'Ölçülü dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Semizotu ve brokoli küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp lor peyniri ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "denge", "tava", "omega-3", "yüksek protein"]', 9, 10, 1, 465, 43.00, 15.00, 25.90),
('be731d61-0806-508f-93ae-7121e4a8c7c5'::uuid, NULL, 'Muzlu elmalı ve havuçlu smoothie', 'muzlu-elmali-ve-havuclu-smoothie-be731d', 'Ofis temposuna uygun ara öğün alternatifi olan bu smoothie, kolay taşınabilir öğün düzeni hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Muz ve elma meyvelerini uygun boyutta hazırlayın.", "Blender haznesine süzme yoğurt, havuç ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "ofis dostu", "enerji", "renkli sebze", "pratik"]', 7, 0, 1, 411, 18.30, 58.00, 11.80),
('96b9fc81-7b8e-56cc-9c4e-8c236e5a0f60'::uuid, NULL, 'Kekikli mercimekli patlıcanlı çorbası', 'kekikli-mercimekli-patlicanli-corbasi-96b9fc', 'Ferah ve renkli yapılı bu çorba, baklagil bazlı yapısıyla lif ve sağlıklı yağ dengesi sunar. Öğle ya da akşam öğününde hafif ama doyurucu bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Patlıcan ve temel aromatik sebzeleri küçük küpler halinde doğrayın.", "Tencerede kısa süre kavurup baklagili ekleyin.", "Üzerini geçecek kadar sıcak su ilave edip kısık ateşte pişirin.", "Kekikli dokunuşunu ekleyip kıvamı oturana kadar kaynatın.", "İsterseniz kısmen blenderdan geçirip sıcak servis edin."]', '["çorba", "öğle yemeği", "akdeniz", "baklagil", "lif", "fırın", "hafif"]', 14, 23, 2, 368, 17.00, 47.00, 12.50),
('30cd5f7e-1d0a-5cc6-a654-c864b994cb40'::uuid, NULL, 'Limonlu somonlu bulgur salata kasesi', 'limonlu-somonlu-bulgur-salata-kasesi-30cd5f', 'Yüksek protein odaklı bu kase, somon fileto ve bulgur ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Bulgur tabanını ayrı bir kapta haşlayıp süzün.", "Somon Fileto için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Ispanak ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "yüksek protein", "omega-3", "lif", "limonlu"]', 11, 19, 2, 531, 32.00, 39.00, 27.40),
('d8945aee-400b-538b-8a75-976ed982c5cf'::uuid, NULL, 'Armutlu çilekli ve ıspanaklı smoothie', 'armutlu-cilekli-ve-ispanakli-smoothie-d8945a', 'Yüksek protein odaklı ara öğün alternatifi olan bu smoothie, kas korunumu ve uzun süreli tokluk hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Armut ve çilek meyvelerini uygun boyutta hazırlayın.", "Blender haznesine lor peyniri, ispanak ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "yüksek protein", "lif", "demir kaynağı", "pratik"]', 9, 0, 1, 340, 23.40, 37.00, 10.90),
('6c173797-a787-5d82-afdb-2e1e02abcb19'::uuid, NULL, 'Kekikli mercimekli brokolili çorbası', 'kekikli-mercimekli-brokolili-corbasi-6c1737', 'Hızlı hazırlanabilen yapılı bu çorba, baklagil bazlı yapısıyla gün içinde sürdürülebilir enerji sunar. Öğle ya da akşam öğününde hafif ama doyurucu bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Brokoli ve temel aromatik sebzeleri küçük küpler halinde doğrayın.", "Tencerede kısa süre kavurup baklagili ekleyin.", "Üzerini geçecek kadar sıcak su ilave edip kısık ateşte pişirin.", "Kekikli dokunuşunu ekleyip kıvamı oturana kadar kaynatın.", "İsterseniz kısmen blenderdan geçirip sıcak servis edin."]', '["çorba", "öğle yemeği", "pratik", "baklagil", "lif", "hafif"]', 11, 28, 3, 378, 19.00, 47.00, 12.70),
('14170293-6b9d-56f5-8d6d-2fcefa864f4e'::uuid, NULL, 'Limonlu fasulyeli karabuğday salata kasesi', 'limonlu-fasulyeli-karabugday-salata-kasesi-141702', 'Sebze ağırlıklı bu kase, kuru fasulye ve karabuğday ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Karabuğday tabanını ayrı bir kapta haşlayıp süzün.", "Kuru Fasulye için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Kabak ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "sebze ağırlıklı", "baklagil", "glutensiz", "limonlu"]', 11, 23, 2, 464, 20.00, 64.00, 14.20),
('876e7d0e-72a1-552f-a59f-f46910578347'::uuid, NULL, 'Labneli fasulyeli semizotlu wrap', 'labneli-fasulyeli-semizotlu-wrap-876e7d', 'Kan şekeri stabilitesi ve kontrollü doygunluk hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kuru Fasulye harcını önceden pişirip ılıtın.", "Semizotu ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine labne sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "denge", "baklagil", "pratik", "taşınabilir"]', 13, 8, 1, 473, 26.00, 62.00, 13.40),
('b0a72fbf-aefc-5a94-bc81-bfd62c712a64'::uuid, NULL, 'Limonlu somonlu sarımsaklı fırın tepsisi', 'limonlu-somonlu-sarimsakli-firin-tepsisi-b0a72f', 'Taşınabilir ve dengeli bu ana öğün, tek tepside pratik hazırlık sunar. Somon Fileto ile sarımsak uyumu hafif akşam yemekleri için güçlü bir seçenektir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Fırını önceden 190 dereceye ısıtın.", "Somon Fileto ve sebzeleri eşit pişecek boyutta hazırlayın.", "Malzemeleri tepsiye yayıp zeytinyağı ve baharatlarla harmanlayın.", "Limonlu dokunuşuyla lezzeti tamamlayın.", "Kızarana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "fırın", "ofis dostu", "omega-3", "aromatik", "limonlu"]', 12, 19, 2, 414, 29.00, 15.00, 26.50),
('e78c23e5-7864-5f69-96a9-44e94c09f0a8'::uuid, NULL, 'Lor peynirli kinoalı dolgulu kabak', 'lor-peynirli-kinoali-dolgulu-kabak-e78c23', 'Akdeniz esintili bu fırın yemeği, porsiyon kontrolünü kolaylaştıran düzenli bir ana öğündür. Kabak içinde hazırlanan iç harç, lif ve sağlıklı yağ dengesi desteği sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak içini hazırlayıp dolguluk hale getirin.", "Lor Peyniri ve kinoa bazlı iç harcı tavada kısa süre çevirin.", "Fesleğenli baharatlarını ekleyip iç harcı dengeleyin.", "Sebzelerin içine paylaştırıp fırın kabına dizin.", "Yumuşayana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "dolma", "akdeniz", "protein", "kompleks karbonhidrat", "fırın"]', 18, 34, 2, 436, 27.00, 45.00, 16.40),
('0d70763b-89db-5aba-970a-971fbad7f437'::uuid, NULL, 'Havuçlu hindili mini köfte', 'havuclu-hindili-mini-kofte-0d7076', 'Tok tutan bu tarif, kontrollü porsiyonda hazırlanabilen çok yönlü bir tabak sunar. Yanına eklenen sos ile ara öğün ya da ana öğün olarak değerlendirilebilir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Hindi Göğsü bazını robotta çekip havuç ile karıştırın.", "Baharatları ekleyip şekil alacak kıvama getirin.", "Karışımdan küçük parçalar alıp köfte formu verin.", "Tavada ya da fırında kontrollü şekilde pişirin.", "Yoğurt Sos ile birlikte servis edin."]', '["pratik", "köfte", "yüksek protein", "renkli sebze", "yüksek tokluk"]', 14, 22, 2, 507, 50.00, 20.00, 25.20),
('10a87551-7b71-55fe-913b-0fe7ba671fc9'::uuid, NULL, 'Fesleğenli tofulu sebze sote', 'feslegenli-tofulu-sebze-sote-10a875', 'Pratik hazırlanabilen bu tava yemeği, tek kapta pişen düzenli bir öğün sunar. Tofu ve sebzelerin diri dokusu sayesinde hafif ama tatmin edicidir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tofu uygun boyutta hazırlayın.", "Renkli Biber ve kabak sebzelerini benzer büyüklükte doğrayın.", "Wok ya da geniş tavayı iyice ısıtıp malzemeleri sırasıyla ekleyin.", "Fesleğenli aroması ile son dokunuşu yapın.", "Sebzeler hafif diri kalacak şekilde servis edin."]', '["ana öğün", "sote", "pratik", "bitkisel protein", "renkli sebze", "tek tava"]', 12, 14, 1, 348, 18.00, 25.00, 19.50),
('0e264255-d37d-513f-9d54-277e3233ccc8'::uuid, NULL, 'Kekikli tavuklu kinoa pilavı', 'kekikli-tavuklu-kinoa-pilavi-0e2642', 'Hafif yapılı bu pilav tabağı, gün içi enerji ihtiyacını kontrollü karşılamak için tasarlandı. Tane tane doku ve dengeli protein miktarıyla günlük planlara kolayca uyum sağlar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kinoa tabanını yıkayıp uygun kıvamda pişirin.", "Tavuk Göğsü ve kabak ile ayrı bir iç harç hazırlayın.", "Pişen tahılı harçla birleştirip birkaç dakika dinlendirin.", "Kekikli ile aromayı canlandırın.", "Ana öğün olarak sıcak servis edin."]', '["öğle yemeği", "pilav", "sebze ağırlıklı", "kompleks karbonhidrat", "yüksek protein", "kekikli"]', 14, 27, 2, 495, 34.00, 33.00, 25.20),
('ccbde982-7a0b-5d6f-b180-8dd004d1038f'::uuid, NULL, 'Tavuklu biberli tam buğday makarna', 'tavuklu-biberli-tam-bugday-makarna-ccbde9', 'Dengeli porsiyonlu bu tabak, klasik makarna hissini daha kontrollü bir içerikle sunar. Sos ve sebze dengesi sayesinde hafif ama tatmin edici bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Makarna tabanını uygun süre boyunca pişirin.", "Tavuk Göğsü ve renkli biber ile sos temelini hazırlayın.", "Yoğurt Sos karışımını tavada kısa süre çevirin.", "Haşlanan tabanı sos ile buluşturup birkaç dakika dinlendirin.", "Sıcak servis edip taze otlarla tamamlayın."]', '["akşam yemeği", "makarna", "denge", "yüksek protein", "tam tahıl", "kekikli"]', 15, 18, 1, 471, 40.00, 50.00, 12.30),
