('7d910001-194b-5fcf-98a6-5043875493d9'::uuid, NULL, 'Yoğurt soslu mercimekli karnabaharlı wrap', 'yogurt-soslu-mercimekli-karnabaharli-wrap-7d9100', 'Kas korunumu ve uzun süreli tokluk hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yeşil Mercimek harcını önceden pişirip ılıtın.", "Karnabahar ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine yoğurt sos sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "yüksek protein", "baklagil", "hafif", "taşınabilir"]', 13, 11, 1, 449, 27.00, 64.00, 9.40),
