('7c2b074a-29bb-5121-a1db-22c1d8ccac5c'::uuid, NULL, 'Tavuklu karnabaharlı kabak spagetti', 'tavuklu-karnabaharli-kabak-spagetti-7c2b07', 'Yüksek protein odaklı bu tabak, klasik makarna hissini daha kontrollü bir içerikle sunar. Sos ve sebze dengesi sayesinde hafif ama tatmin edici bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak Spagetti tabanını uygun süre boyunca pişirin.", "Tavuk Göğsü ve karnabahar ile sos temelini hazırlayın.", "Labne karışımını tavada kısa süre çevirin.", "Haşlanan tabanı sos ile buluşturup birkaç dakika dinlendirin.", "Sıcak servis edip taze otlarla tamamlayın."]', '["akşam yemeği", "makarna", "yüksek protein", "düşük karbonhidrat", "fesleğenli"]', 12, 20, 1, 367, 36.00, 21.00, 15.40),
