('363f9828-0fb0-503b-aa8b-b111b4c09a5c'::uuid, NULL, 'Yoğurt soslu ton balıklı sandviç', 'yogurt-soslu-ton-balikli-sandvic-363f98', 'Akdeniz esintili bu sandviç, dışarıda yemek gereken günlerde planı korumayı kolaylaştırır. Tam Buğday Ekmeği tabanı ve dengeli iç harcı sayesinde hızlı ama doyurucu bir seçenek sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Ekmeği dilimlerini hafifçe ısıtın.", "Yüzeye önce yoğurt sos, ardından ton balığı katmanını ekleyin.", "Kabak ile taze bir katman oluşturun.", "Sandviçi sıkı şekilde kapatıp ikiye bölün.", "İsteğe göre yanında ayran veya salata ile servis edin."]', '["öğle yemeği", "sandviç", "akdeniz", "balık", "taşınabilir"]', 11, 4, 1, 412, 35.00, 36.00, 14.20),
