('f1d1a4fd-1356-52f5-a952-05c2df4bfa77'::uuid, NULL, 'Tarçınlı böğürtlenli yulaf ve süzme yoğurt kasesi', 'tarcinli-bogurtlenli-yulaf-ve-suzme-yogurt-kasesi-f1d1a4', 'Ofis temposuna uygun bu kahvaltı, kolay taşınabilir öğün düzeni için tasarlandı. Böğürtlen, yulaf ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile böğürtlen parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce yulaf tabanını, üzerine süzme yoğurt karışımını alın.", "Keten Tohumu ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "ofis dostu", "fermente", "antioksidan"]', 14, 3, 1, 458, 24.00, 49.00, 18.50),
('b628582b-f16c-5c34-b19b-264b5eac9390'::uuid, NULL, 'Hardallı biberli ve soğanlı omlet', 'hardalli-biberli-ve-soganli-omlet-b62858', 'Ferah ve renkli dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Renkli Biber ve soğan küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp lor peyniri ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "akdeniz", "tava", "renkli sebze", "yüksek protein"]', 8, 9, 1, 482, 41.00, 20.00, 26.50),
('6eabf5db-35a9-5ef3-b5bf-5cb29f2c26d6'::uuid, NULL, 'Çilekli muzlu ve semizotlu smoothie', 'cilekli-muzlu-ve-semizotlu-smoothie-6eabf5', 'Yüksek protein odaklı ara öğün alternatifi olan bu smoothie, kas korunumu ve uzun süreli tokluk hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Çilek ve muz meyvelerini uygun boyutta hazırlayın.", "Blender haznesine lor peyniri, semizotu ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "yüksek protein", "meyveli", "omega-3", "pratik"]', 7, 0, 1, 368, 24.00, 43.00, 11.10);
