('699f01b1-3849-57b8-a1cc-1520925504ac'::uuid, NULL, 'Sumaklı tofulu karabuğday pilavı', 'sumakli-tofulu-karabugday-pilavi-699f01', 'Hafif yapılı bu pilav tabağı, gün içi enerji ihtiyacını kontrollü karşılamak için tasarlandı. Tane tane doku ve dengeli protein miktarıyla günlük planlara kolayca uyum sağlar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Karabuğday tabanını yıkayıp uygun kıvamda pişirin.", "Tofu ve semizotu ile ayrı bir iç harç hazırlayın.", "Pişen tahılı harçla birleştirip birkaç dakika dinlendirin.", "Sumaklı ile aromayı canlandırın.", "Ana öğün olarak sıcak servis edin."]', '["öğle yemeği", "pilav", "sebze ağırlıklı", "glutensiz", "bitkisel protein", "sumaklı"]', 12, 19, 2, 486, 23.00, 39.00, 26.40),
('2f10a037-34d3-5a50-85b1-080029f48697'::uuid, NULL, 'Tofulu pancarlı kabak spagetti', 'tofulu-pancarli-kabak-spagetti-2f10a0', 'Dengeli porsiyonlu bu tabak, klasik makarna hissini daha kontrollü bir içerikle sunar. Sos ve sebze dengesi sayesinde hafif ama tatmin edici bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak Spagetti tabanını uygun süre boyunca pişirin.", "Tofu ve pancar ile sos temelini hazırlayın.", "Domates Sosu karışımını tavada kısa süre çevirin.", "Haşlanan tabanı sos ile buluşturup birkaç dakika dinlendirin.", "Sıcak servis edip taze otlarla tamamlayın."]', '["akşam yemeği", "makarna", "denge", "bitkisel protein", "düşük karbonhidrat", "fesleğenli"]', 15, 12, 2, 326, 21.00, 33.00, 12.20),
('2f326d34-f1bf-58b2-b07f-3d0a60818bde'::uuid, NULL, 'Tofulu mantarlı kabak spagetti', 'tofulu-mantarli-kabak-spagetti-2f326d', 'Ofis temposuna uygun bu tabak, klasik makarna hissini daha kontrollü bir içerikle sunar. Sos ve sebze dengesi sayesinde hafif ama tatmin edici bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak Spagetti tabanını uygun süre boyunca pişirin.", "Tofu ve mantar ile sos temelini hazırlayın.", "Yoğurt Sos karışımını tavada kısa süre çevirin.", "Haşlanan tabanı sos ile buluşturup birkaç dakika dinlendirin.", "Sıcak servis edip taze otlarla tamamlayın."]', '["akşam yemeği", "makarna", "ofis dostu", "bitkisel protein", "düşük karbonhidrat", "karabiberli"]', 10, 21, 2, 320, 25.00, 25.00, 13.30),
('b80ee2c9-722d-56db-8dd9-0c14850c25aa'::uuid, NULL, 'Yoğurt soslu lor peynirli sandviç', 'yogurt-soslu-lor-peynirli-sandvic-b80ee2', 'Akdeniz esintili bu sandviç, dışarıda yemek gereken günlerde planı korumayı kolaylaştırır. Tam Buğday Ekmeği tabanı ve dengeli iç harcı sayesinde hızlı ama doyurucu bir seçenek sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Ekmeği dilimlerini hafifçe ısıtın.", "Yüzeye önce yoğurt sos, ardından lor peyniri katmanını ekleyin.", "Patlıcan ile taze bir katman oluşturun.", "Sandviçi sıkı şekilde kapatıp ikiye bölün.", "İsteğe göre yanında ayran veya salata ile servis edin."]', '["öğle yemeği", "sandviç", "akdeniz", "protein", "taşınabilir"]', 11, 4, 1, 412, 31.00, 42.00, 13.30),
('9ad244b7-eca7-5dd7-b992-43a526f8479e'::uuid, NULL, 'Elmalı chia tohumu puding', 'elmali-chia-tohumu-puding-9ad244', 'Tok tutan ara öğün olarak hazırlanan bu puding, kontrollü tatlı isteği için iyi bir alternatiftir. Protein ve lif desteğiyle gereksiz atıştırmayı azaltmaya yardımcı olur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Chia Tohumu tabanını sıvı bileşenle karıştırıp dinlenmeye bırakın.", "Lor Peyniri ile yumuşak bir kıvam hazırlayın.", "Elma dilimleri ve tabanı katmanlı şekilde birleştirin.", "Hindistan Cevizi ile dokusal kontrast ekleyin.", "Soğutup servis edin."]', '["ara öğün", "puding", "yüksek protein", "omega-3", "lif", "tatlı ihtiyacına çözüm"]', 10, 0, 1, 457, 25.30, 39.00, 22.20),
('0209e066-4108-5282-80ae-7f5bd487e1c3'::uuid, NULL, 'Limonlu hindili ana tabak', 'limonlu-hindili-ana-tabak-0209e0', 'Hızlı hazırlanabilen bu tarif, akşam öğününde daha düzenli bir tabak kurmak isteyenler için hazırlandı. Hindi Göğsü ile karabuğday eşleşmesi dengeli makro dağılımı sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Hindi Göğsü ana malzemesini tercih ettiğiniz yöntemle pişirin.", "Karabuğday garnitürünü ayrı kapta hazırlayın.", "Havuç eşlikçisini diri kalacak şekilde pişirin.", "Tüm parçaları tabakta dengeli porsiyonla birleştirin.", "Servis öncesi son baharat dokunuşunu ekleyin."]', '["akşam yemeği", "ana tabak", "pratik", "yüksek protein", "glutensiz", "limonlu"]', 12, 16, 2, 511, 33.00, 38.00, 25.20),
('876677f9-02cf-5b37-82b7-6a1e00499b5b'::uuid, NULL, 'Armutlu narlı ve semizotlu smoothie', 'armutlu-narli-ve-semizotlu-smoothie-876677', 'Sebze ağırlıklı ara öğün alternatifi olan bu smoothie, mikrobesin çeşitliliği ve sindirim konforu hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Armut ve nar meyvelerini uygun boyutta hazırlayın.", "Blender haznesine süzme yoğurt, semizotu ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "sebze ağırlıklı", "lif", "omega-3", "pratik"]', 10, 0, 1, 370, 19.40, 46.00, 12.10),
('1f12b6e2-a2e7-52bf-9b52-b63b76fa3621'::uuid, NULL, 'Tarçınlı yaban mersinli yulaf ve süzme yoğurt kasesi', 'tarcinli-yaban-mersinli-yulaf-ve-suzme-yogurt-kasesi-1f12b6', 'Dengeli porsiyonlu bu kahvaltı, kan şekeri stabilitesi ve kontrollü doygunluk için tasarlandı. Yaban mersini, yulaf ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile yaban mersini parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce yulaf tabanını, üzerine süzme yoğurt karışımını alın.", "Ceviz ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "denge", "fermente", "antioksidan"]', 10, 1, 1, 502, 25.00, 50.00, 22.40),
('651aafe7-e4ee-5c93-b47b-678af0717477'::uuid, NULL, 'Hardallı soğanlı ve kabaklı omlet', 'hardalli-soganli-ve-kabakli-omlet-651aaf', 'Taşınabilir dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Soğan ve kabak küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp süzme yoğurt ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "ofis dostu", "tava", "aromatik", "yüksek protein"]', 13, 14, 1, 483, 37.00, 22.00, 27.40),
('dcd64494-6c67-5167-84e5-4ab637aa8ed6'::uuid, NULL, 'Narlı böğürtlenli ve semizotlu smoothie', 'narli-bogurtlenli-ve-semizotlu-smoothie-dcd644', 'Akdeniz esintili ara öğün alternatifi olan bu smoothie, lif ve sağlıklı yağ dengesi hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Nar ve böğürtlen meyvelerini uygun boyutta hazırlayın.", "Blender haznesine süzme yoğurt, semizotu ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "akdeniz", "antioksidan", "omega-3", "pratik"]', 9, 0, 1, 348, 20.00, 39.00, 12.40),
('77d7d2f9-a753-573c-b208-b1d50c7db4bb'::uuid, NULL, 'Zerdeçallı mercimekli brokolili çorbası', 'zerdecalli-mercimekli-brokolili-corbasi-77d7d2', 'Tok tutan yapılı bu çorba, baklagil bazlı yapısıyla kas korunumu ve uzun süreli tokluk sunar. Öğle ya da akşam öğününde hafif ama doyurucu bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Brokoli ve temel aromatik sebzeleri küçük küpler halinde doğrayın.", "Tencerede kısa süre kavurup baklagili ekleyin.", "Üzerini geçecek kadar sıcak su ilave edip kısık ateşte pişirin.", "Zerdeçallı dokunuşunu ekleyip kıvamı oturana kadar kaynatın.", "İsterseniz kısmen blenderdan geçirip sıcak servis edin."]', '["çorba", "öğle yemeği", "yüksek protein", "baklagil", "lif", "hafif"]', 10, 34, 3, 378, 19.00, 47.00, 12.70),
('d9a017c5-3cd1-587b-8242-af21ba253275'::uuid, NULL, 'Yoğurt soslu lor peynirli sarımsaklı wrap', 'yogurt-soslu-lor-peynirli-sarimsakli-wrap-d9a017', 'Gün içinde sürdürülebilir enerji hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Lor Peyniri harcını önceden pişirip ılıtın.", "Sarımsak ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine yoğurt sos sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "pratik", "protein", "hafif", "taşınabilir"]', 13, 10, 1, 428, 31.00, 42.00, 15.10),
('678e642e-90ee-534e-a025-82cd4980f1b3'::uuid, NULL, 'Avokadolu mercimekli kabaklı wrap', 'avokadolu-mercimekli-kabakli-wrap-678e64', 'Mikrobesin çeşitliliği ve sindirim konforu hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yeşil Mercimek harcını önceden pişirip ılıtın.", "Kabak ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine avokado ezmesi sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "sebze ağırlıklı", "baklagil", "sağlıklı yağ", "taşınabilir"]', 10, 8, 1, 519, 24.00, 67.00, 17.20),
