('6ba9df14-2418-5735-8691-87f3a139c3da'::uuid, NULL, 'Zerdeçallı mercimekli ıspanaklı çorbası', 'zerdecalli-mercimekli-ispanakli-corbasi-6ba9df', 'Hafif yapılı bu çorba, baklagil bazlı yapısıyla mikrobesin çeşitliliği ve sindirim konforu sunar. Öğle ya da akşam öğününde hafif ama doyurucu bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Ispanak ve temel aromatik sebzeleri küçük küpler halinde doğrayın.", "Tencerede kısa süre kavurup baklagili ekleyin.", "Üzerini geçecek kadar sıcak su ilave edip kısık ateşte pişirin.", "Zerdeçallı dokunuşunu ekleyip kıvamı oturana kadar kaynatın.", "İsterseniz kısmen blenderdan geçirip sıcak servis edin."]', '["çorba", "öğle yemeği", "sebze ağırlıklı", "baklagil", "lif", "demir kaynağı", "hafif"]', 13, 31, 2, 361, 18.00, 44.00, 12.60),
('c3f5eb22-0301-5d0b-9c69-df35c14f0ff8'::uuid, NULL, 'Biberiyeli tavuklu tam buğday makarna salata kasesi', 'biberiyeli-tavuklu-tam-bugday-makarna-salata-kasesi-c3f5eb', 'Dengeli porsiyonlu bu kase, tavuk göğsü ve tam buğday makarna ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Makarna tabanını ayrı bir kapta haşlayıp süzün.", "Tavuk Göğsü için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Bezelye ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "denge", "yüksek protein", "tam tahıl", "biberiyeli"]', 16, 21, 1, 559, 40.00, 56.00, 19.40),
('41e35cae-f3f9-59b6-9801-6a08ecc17d60'::uuid, NULL, 'Yoğurt soslu yumurtalı ıspanaklı wrap', 'yogurt-soslu-yumurtali-ispanakli-wrap-41e35c', 'Kolay taşınabilir öğün düzeni hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yumurta harcını önceden pişirip ılıtın.", "Ispanak ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine yoğurt sos sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "ofis dostu", "kahvaltı", "hafif", "taşınabilir"]', 10, 11, 1, 460, 30.00, 39.00, 20.40),
('85c8bb44-4f09-560c-bde5-59469de3fc0d'::uuid, NULL, 'Biberiyeli tofulu patlıcanlı fırın tepsisi', 'biberiyeli-tofulu-patlicanli-firin-tepsisi-85c8bb', 'Ferah ve renkli ve dengeli bu ana öğün, tek tepside pratik hazırlık sunar. Tofu ile patlıcan uyumu hafif akşam yemekleri için güçlü bir seçenektir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Fırını önceden 190 dereceye ısıtın.", "Tofu ve sebzeleri eşit pişecek boyutta hazırlayın.", "Malzemeleri tepsiye yayıp zeytinyağı ve baharatlarla harmanlayın.", "Biberiyeli dokunuşuyla lezzeti tamamlayın.", "Kızarana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "fırın", "akdeniz", "bitkisel protein", "biberiyeli"]', 17, 26, 2, 397, 22.00, 33.00, 19.70),
('605cf5de-4e53-5c93-bd35-cc929987fc0e'::uuid, NULL, 'Hindili bulgurlu dolgulu kabak', 'hindili-bulgurlu-dolgulu-kabak-605cf5', 'Yüksek protein odaklı bu fırın yemeği, porsiyon kontrolünü kolaylaştıran düzenli bir ana öğündür. Kabak içinde hazırlanan iç harç, kas korunumu ve uzun süreli tokluk desteği sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak içini hazırlayıp dolguluk hale getirin.", "Hindi Göğsü ve bulgur bazlı iç harcı tavada kısa süre çevirin.", "Fesleğenli baharatlarını ekleyip iç harcı dengeleyin.", "Sebzelerin içine paylaştırıp fırın kabına dizin.", "Yumuşayana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "dolma", "yüksek protein", "lif", "fırın"]', 22, 28, 3, 420, 33.00, 44.00, 12.40),
('a9a3dfaa-fc1f-5e50-8b8a-5f7de40eed08'::uuid, NULL, 'Kekikli yumurtalı esmer pirinç pilavı', 'kekikli-yumurtali-esmer-pirinc-pilavi-a9a3df', 'Hızlı hazırlanabilen yapılı bu pilav tabağı, gün içi enerji ihtiyacını kontrollü karşılamak için tasarlandı. Tane tane doku ve dengeli protein miktarıyla günlük planlara kolayca uyum sağlar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Esmer Pirinç tabanını yıkayıp uygun kıvamda pişirin.", "Yumurta ve karnabahar ile ayrı bir iç harç hazırlayın.", "Pişen tahılı harçla birleştirip birkaç dakika dinlendirin.", "Kekikli ile aromayı canlandırın.", "Ana öğün olarak sıcak servis edin."]', '["öğle yemeği", "pilav", "pratik", "denge", "kahvaltı", "kekikli"]', 13, 18, 3, 534, 24.00, 41.00, 30.40),
