('1fbabb45-63cf-5d93-a317-d39667942ba9'::uuid, NULL, 'Lor peynirli ıspanaklı tam buğday makarna', 'lor-peynirli-ispanakli-tam-bugday-makarna-1fbabb', 'Ofis temposuna uygun bu tabak, klasik makarna hissini daha kontrollü bir içerikle sunar. Sos ve sebze dengesi sayesinde hafif ama tatmin edici bir alternatif oluşturur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Makarna tabanını uygun süre boyunca pişirin.", "Lor Peyniri ve ispanak ile sos temelini hazırlayın.", "Yoğurt Sos karışımını tavada kısa süre çevirin.", "Haşlanan tabanı sos ile buluşturup birkaç dakika dinlendirin.", "Sıcak servis edip taze otlarla tamamlayın."]', '["akşam yemeği", "makarna", "ofis dostu", "protein", "tam tahıl", "karabiberli"]', 10, 15, 2, 457, 33.00, 51.00, 13.40),
