('563f0815-b646-5869-80b4-3d76909c4eea'::uuid, NULL, 'Limonlu somonlu ana tabak', 'limonlu-somonlu-ana-tabak-563f08', 'Tok tutan bu tarif, akşam öğününde daha düzenli bir tabak kurmak isteyenler için hazırlandı. Somon Fileto ile bulgur eşleşmesi dengeli makro dağılımı sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Somon Fileto ana malzemesini tercih ettiğiniz yöntemle pişirin.", "Bulgur garnitürünü ayrı kapta hazırlayın.", "Patlıcan eşlikçisini diri kalacak şekilde pişirin.", "Tüm parçaları tabakta dengeli porsiyonla birleştirin.", "Servis öncesi son baharat dokunuşunu ekleyin."]', '["akşam yemeği", "ana tabak", "yüksek protein", "omega-3", "lif", "limonlu"]', 12, 20, 2, 585, 31.00, 38.00, 34.30),
