('58bc6f67-f5e1-5701-a45e-51b1257ddd59'::uuid, NULL, 'Mandalinalı elmalı ve semizotlu smoothie', 'mandalinali-elmali-ve-semizotlu-smoothie-58bc6f', 'Dengeli porsiyonlu ara öğün alternatifi olan bu smoothie, kan şekeri stabilitesi ve kontrollü doygunluk hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Mandalina ve elma meyvelerini uygun boyutta hazırlayın.", "Blender haznesine süzme yoğurt, semizotu ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "denge", "c vitamini", "omega-3", "pratik"]', 10, 0, 1, 356, 19.30, 43.00, 11.90),
('1aa8a2b2-5bba-54ec-b743-c0e5df256079'::uuid, NULL, 'Limonlu somonlu kabak spagetti salata kasesi', 'limonlu-somonlu-kabak-spagetti-salata-kasesi-1aa8a2', 'Ofis temposuna uygun bu kase, somon fileto ve kabak spagetti ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak Spagetti tabanını ayrı bir kapta haşlayıp süzün.", "Somon Fileto için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Sarımsak ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "ofis dostu", "omega-3", "düşük karbonhidrat", "limonlu"]', 14, 23, 1, 424, 29.00, 16.00, 27.10),
('1eb854d8-9fcd-5201-97bd-e266016b4105'::uuid, NULL, 'Biberiyeli tavuklu bulgur salata kasesi', 'biberiyeli-tavuklu-bulgur-salata-kasesi-1eb854', 'Akdeniz esintili bu kase, tavuk göğsü ve bulgur ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Bulgur tabanını ayrı bir kapta haşlayıp süzün.", "Tavuk Göğsü için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Brokoli ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "akdeniz", "yüksek protein", "lif", "biberiyeli"]', 11, 14, 2, 474, 35.00, 42.00, 18.50),
('7e27626d-1b3c-5265-b943-726241a41364'::uuid, NULL, 'Avokadolu fasulyeli biberli wrap', 'avokadolu-fasulyeli-biberli-wrap-7e2762', 'Kas korunumu ve uzun süreli tokluk hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kuru Fasulye harcını önceden pişirip ılıtın.", "Renkli Biber ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine avokado ezmesi sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "yüksek protein", "baklagil", "sağlıklı yağ", "taşınabilir"]', 12, 12, 1, 524, 23.00, 69.00, 17.30),
