('114aa87e-335e-54e8-8b6c-a5c126ba1d71'::uuid, NULL, 'Hardallı brokolili ve biberli omlet', 'hardalli-brokolili-ve-biberli-omlet-114aa8', 'Taşınabilir dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Brokoli ve renkli biber küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp süzme yoğurt ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "ofis dostu", "tava", "lif", "yüksek protein"]', 8, 12, 1, 490, 39.00, 21.00, 27.80),
