('6ab5f67e-5109-5083-9ed6-1af227889b2f'::uuid, NULL, 'Labneli lor peynirli sandviç', 'labneli-lor-peynirli-sandvic-6ab5f6', 'Dengeli porsiyonlu bu sandviç, dışarıda yemek gereken günlerde planı korumayı kolaylaştırır. Çavdar Ekmeği tabanı ve dengeli iç harcı sayesinde hızlı ama doyurucu bir seçenek sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Çavdar Ekmeği dilimlerini hafifçe ısıtın.", "Yüzeye önce labne, ardından lor peyniri katmanını ekleyin.", "Sarımsak ile taze bir katman oluşturun.", "Sandviçi sıkı şekilde kapatıp ikiye bölün.", "İsteğe göre yanında ayran veya salata ile servis edin."]', '["öğle yemeği", "sandviç", "denge", "protein", "taşınabilir"]', 7, 6, 1, 405, 30.00, 35.00, 16.10),
('e306bb77-4109-5ed7-ae37-aaefe34cd6c6'::uuid, NULL, 'Tarçınlı kivili kinoa ve lor peyniri kasesi', 'tarcinli-kivili-kinoa-ve-lor-peyniri-kasesi-e306bb', 'Ofis temposuna uygun bu kahvaltı, kolay taşınabilir öğün düzeni için tasarlandı. Kivi, kinoa ve lor peyniri birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kinoa tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Lor Peyniri ile kivi parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce kinoa tabanını, üzerine lor peyniri karışımını alın.", "Badem ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "ofis dostu", "kompleks karbonhidrat", "protein", "c vitamini"]', 7, 3, 1, 513, 30.00, 50.00, 21.40),
('602ee58b-d38d-544a-bdb7-d04ef4f9bb49'::uuid, NULL, 'Vanilyalı mandalinalı yulaf ve lor peyniri kasesi', 'vanilyali-mandalinali-yulaf-ve-lor-peyniri-kasesi-602ee5', 'Akdeniz esintili bu kahvaltı, lif ve sağlıklı yağ dengesi için tasarlandı. Mandalina, yulaf ve lor peyniri birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Lor Peyniri ile mandalina parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce yulaf tabanını, üzerine lor peyniri karışımını alın.", "Kabak Çekirdeği ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "akdeniz", "protein", "c vitamini"]', 10, 4, 1, 503, 31.00, 49.00, 20.30),
('51e68bd6-73fa-5eee-9276-4d78b6649747'::uuid, NULL, 'Naneli elmalı chia tohumu ve süzme yoğurt kasesi', 'naneli-elmali-chia-tohumu-ve-suzme-yogurt-kasesi-51e68b', 'Yüksek protein odaklı bu kahvaltı, kas korunumu ve uzun süreli tokluk için tasarlandı. Elma, chia tohumu ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Chia Tohumu tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile elma parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce chia tohumu tabanını, üzerine süzme yoğurt karışımını alın.", "Badem ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "yüksek protein", "omega-3", "fermente", "lif"]', 7, 3, 1, 510, 24.30, 42.00, 27.20),
('b3fc7229-e812-5cd0-b45e-64729c23dbcc'::uuid, NULL, 'Naneli ıspanaklı ve havuçlu omlet', 'naneli-ispanakli-ve-havuclu-omlet-b3fc72', 'Hızlı hazırlanabilen dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Ispanak ve havuç küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp lor peyniri ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "pratik", "tava", "demir kaynağı", "yüksek protein"]', 11, 12, 1, 458, 41.00, 16.00, 25.60),
('b29e6e63-0cba-59ec-a945-2f3015385b1f'::uuid, NULL, 'Mandalinalı muzlu ve havuçlu smoothie', 'mandalinali-muzlu-ve-havuclu-smoothie-b29e6e', 'Sebze ağırlıklı ara öğün alternatifi olan bu smoothie, mikrobesin çeşitliliği ve sindirim konforu hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Mandalina ve muz meyvelerini uygun boyutta hazırlayın.", "Blender haznesine lor peyniri, havuç ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "sebze ağırlıklı", "c vitamini", "renkli sebze", "pratik"]', 6, 0, 1, 394, 23.00, 51.00, 10.90),
('dde86489-f2c7-523b-86c6-77aa8f17a611'::uuid, NULL, 'Fesleğenli mercimekli tam buğday lavaş salata kasesi', 'feslegenli-mercimekli-tam-bugday-lavas-salata-kasesi-dde864', 'Dengeli porsiyonlu bu kase, yeşil mercimek ve tam buğday lavaş ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Tam Buğday Lavaş tabanını ayrı bir kapta haşlayıp süzün.", "Yeşil Mercimek için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Havuç ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "denge", "baklagil", "pratik", "fesleğenli"]', 10, 19, 1, 494, 22.00, 65.00, 16.20),
