('e0d972cc-b8ad-5009-a7bc-4382e8ce7f38'::uuid, NULL, 'Avokadolu fasulyeli patlıcanlı wrap', 'avokadolu-fasulyeli-patlicanli-wrap-e0d972', 'Lif ve sağlıklı yağ dengesi hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kuru Fasulye harcını önceden pişirip ılıtın.", "Patlıcan ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine avokado ezmesi sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "akdeniz", "baklagil", "sağlıklı yağ", "taşınabilir"]', 10, 15, 1, 528, 23.00, 70.00, 17.30),
