('e9dd57f7-3971-5052-a51d-6763cd6ee26f'::uuid, NULL, 'Kekikli sarımsaklı ve bezelyeli omlet', 'kekikli-sarimsakli-ve-bezelyeli-omlet-e9dd57', 'Ölçülü dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Sarımsak ve bezelye küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp süzme yoğurt ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "denge", "tava", "aromatik", "yüksek protein"]', 11, 10, 1, 506, 40.00, 27.00, 26.50),
('62f2cf61-0565-538f-bbf2-c5760f6956ff'::uuid, NULL, 'Kivili yulaf puding', 'kivili-yulaf-puding-62f2cf', 'Taşınabilir ara öğün olarak hazırlanan bu puding, kontrollü tatlı isteği için iyi bir alternatiftir. Protein ve lif desteğiyle gereksiz atıştırmayı azaltmaya yardımcı olur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Yulaf tabanını sıvı bileşenle karıştırıp dinlenmeye bırakın.", "Süzme Yoğurt ile yumuşak bir kıvam hazırlayın.", "Kivi dilimleri ve tabanı katmanlı şekilde birleştirin.", "Hindistan Cevizi ile dokusal kontrast ekleyin.", "Soğutup servis edin."]', '["ara öğün", "puding", "ofis dostu", "kahvaltı", "c vitamini", "tatlı ihtiyacına çözüm"]', 11, 0, 1, 475, 23.00, 52.00, 19.40),
('0bff35b2-9547-5d22-b29e-a2d62fa435c6'::uuid, NULL, 'Naneli şeftalili chia tohumu ve lor peyniri kasesi', 'naneli-seftalili-chia-tohumu-ve-lor-peyniri-kasesi-0bff35', 'Akdeniz esintili bu kahvaltı, lif ve sağlıklı yağ dengesi için tasarlandı. Şeftali, chia tohumu ve lor peyniri birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Chia Tohumu tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Lor Peyniri ile şeftali parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce chia tohumu tabanını, üzerine lor peyniri karışımını alın.", "Kabak Çekirdeği ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "akdeniz", "omega-3", "protein", "yaz meyvesi"]', 7, 0, 1, 479, 30.00, 35.00, 24.30),
('858550ba-26e7-5780-b7b1-0b1e4510cd84'::uuid, NULL, 'Naneli yaban mersinli chia tohumu ve lor peyniri kasesi', 'naneli-yaban-mersinli-chia-tohumu-ve-lor-peyniri-kasesi-858550', 'Yüksek protein odaklı bu kahvaltı, kas korunumu ve uzun süreli tokluk için tasarlandı. Yaban mersini, chia tohumu ve lor peyniri birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Chia Tohumu tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Lor Peyniri ile yaban mersini parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce chia tohumu tabanını, üzerine lor peyniri karışımını alın.", "Kabak Çekirdeği ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "yüksek protein", "omega-3", "protein", "antioksidan"]', 7, 1, 1, 468, 30.00, 32.00, 24.40),
('3404e605-7d9a-5854-bdae-582c28d45960'::uuid, NULL, 'Tarçınlı elmalı kinoa ve süzme yoğurt kasesi', 'tarcinli-elmali-kinoa-ve-suzme-yogurt-kasesi-3404e6', 'Pratik hazırlanabilen bu kahvaltı, gün içinde sürdürülebilir enerji için tasarlandı. Elma, kinoa ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kinoa tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile elma parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce kinoa tabanını, üzerine süzme yoğurt karışımını alın.", "Kabak Çekirdeği ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "pratik", "kompleks karbonhidrat", "fermente", "lif"]', 10, 4, 1, 515, 26.30, 57.00, 20.20),
('c597f8fa-b529-5164-9e34-e2eb61fb1d2b'::uuid, NULL, 'Tarçınlı yaban mersinli kinoa ve süzme yoğurt kasesi', 'tarcinli-yaban-mersinli-kinoa-ve-suzme-yogurt-kasesi-c597f8', 'Sebze ağırlıklı bu kahvaltı, mikrobesin çeşitliliği ve sindirim konforu için tasarlandı. Yaban mersini, kinoa ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kinoa tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile yaban mersini parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce kinoa tabanını, üzerine süzme yoğurt karışımını alın.", "Keten Tohumu ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "sebze ağırlıklı", "kompleks karbonhidrat", "fermente", "antioksidan"]', 7, 0, 1, 453, 24.00, 50.00, 17.40),
('34f673a3-6ecf-55a0-b4cc-fa7975df1327'::uuid, NULL, 'Hardallı patlıcanlı ve havuçlu omlet', 'hardalli-patlicanli-ve-havuclu-omlet-34f673', 'Ölçülü dokulu bu tarif, yumurta ve sebzeleri tek tavada bir araya getirir. Günün ilk yarısında dengeli bir protein kaynağı arayanlar için uygundur.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Patlıcan ve havuç küçük parçalar halinde doğrayın.", "Yapışmaz tavayı ısıtıp sebzeleri kısa süre soteleyin.", "Yumurtaları çırpıp süzme yoğurt ile pürüzsüz hale getirin.", "Karışımı tavaya dökün ve kısık ateşte kontrollü şekilde pişirin.", "Omleti ikiye katlayıp sıcak servis edin."]', '["kahvaltı", "omlet", "denge", "tava", "fırın", "yüksek protein"]', 13, 12, 1, 488, 37.00, 23.00, 27.50),
('64416d0d-82de-5fcd-83d1-b95dd328a53c'::uuid, NULL, 'Armutlu böğürtlenli ve havuçlu smoothie', 'armutlu-bogurtlenli-ve-havuclu-smoothie-64416d', 'Ofis temposuna uygun ara öğün alternatifi olan bu smoothie, kolay taşınabilir öğün düzeni hedefini destekler. Meyve ve yeşil sebzeyi dengeli şekilde bir araya getirir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Armut ve böğürtlen meyvelerini uygun boyutta hazırlayın.", "Blender haznesine süzme yoğurt, havuç ve meyveleri ekleyin.", "İsteğe göre birkaç buz küpü ve su ilavesi yapın.", "Karışım pürüzsüz olana kadar blenderdan geçirin.", "Bekletmeden servis edin."]', '["ara öğün", "smoothie", "ofis dostu", "lif", "renkli sebze", "pratik"]', 6, 0, 1, 365, 18.40, 46.00, 11.90),
('0e055ca2-256b-5771-9199-72600326d3bf'::uuid, NULL, 'Limonlu fasulyeli bulgur salata kasesi', 'limonlu-fasulyeli-bulgur-salata-kasesi-0e055c', 'Akdeniz esintili bu kase, kuru fasulye ve bulgur ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Bulgur tabanını ayrı bir kapta haşlayıp süzün.", "Kuru Fasulye için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Sarımsak ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "akdeniz", "baklagil", "lif", "limonlu"]', 11, 14, 1, 450, 19.00, 64.00, 13.10),
('316ba55e-28f1-5eca-8700-60e3d8fd8f49'::uuid, NULL, 'Fesleğenli somonlu kabak spagetti salata kasesi', 'feslegenli-somonlu-kabak-spagetti-salata-kasesi-316ba5', 'Yüksek protein odaklı bu kase, somon fileto ve kabak spagetti ile uzun süreli tokluk sağlar. Renkli sebzeler sayesinde tabağa canlı bir görünüm ve iyi bir lif dengesi ekler.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kabak Spagetti tabanını ayrı bir kapta haşlayıp süzün.", "Somon Fileto için tercih ettiğiniz pişirme yöntemini uygulayıp dilimleyin.", "Brokoli ve eşlik edecek yeşillikleri hazırlayın.", "Sos malzemelerini karıştırıp kaseyi katmanlı şekilde birleştirin.", "Sosu servis öncesinde gezdirip hemen sunun."]', '["öğle yemeği", "salata kasesi", "yüksek protein", "omega-3", "düşük karbonhidrat", "fesleğenli"]', 10, 16, 1, 448, 31.00, 19.00, 27.50),
('fc4bf414-26a9-5617-96c8-13fd62fcc3db'::uuid, NULL, 'Avokadolu nohutlu ıspanaklı wrap', 'avokadolu-nohutlu-ispanakli-wrap-fc4bf4', 'Gün içinde sürdürülebilir enerji hedefleyen bu wrap, taşınabilir yapısıyla yoğun günlerde iyi çalışır. İç dolgu dengeli karbonhidrat, protein ve sebzeyi aynı lokmada toplar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Nohut harcını önceden pişirip ılıtın.", "Ispanak ve diğer eşlikçileri ince jülyen halinde hazırlayın.", "Tam Buğday Lavaş yüzeyine avokado ezmesi sürün.", "Dolgu malzemelerini merkezde toplayıp sıkı şekilde sarın.", "İkiye bölüp ılık ya da soğuk servis edin."]', '["öğle yemeği", "wrap", "pratik", "baklagil", "sağlıklı yağ", "taşınabilir"]', 9, 9, 1, 543, 23.00, 69.00, 19.40),
('7dabaa67-9ced-558e-ba51-6e66bd1ec846'::uuid, NULL, 'Biberiyeli tofulu havuçlu fırın tepsisi', 'biberiyeli-tofulu-havuclu-firin-tepsisi-7dabaa', 'Hafif ve dengeli bu ana öğün, tek tepside pratik hazırlık sunar. Tofu ile havuç uyumu hafif akşam yemekleri için güçlü bir seçenektir.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Fırını önceden 190 dereceye ısıtın.", "Tofu ve sebzeleri eşit pişecek boyutta hazırlayın.", "Malzemeleri tepsiye yayıp zeytinyağı ve baharatlarla harmanlayın.", "Biberiyeli dokunuşuyla lezzeti tamamlayın.", "Kızarana kadar pişirip sıcak servis edin."]', '["akşam yemeği", "fırın", "sebze ağırlıklı", "bitkisel protein", "renkli sebze", "biberiyeli"]', 14, 22, 3, 340, 19.00, 22.00, 19.60),
('b1c1d248-a1ca-5564-a7ce-a3412ecdd388'::uuid, NULL, 'Vanilyalı çilekli kinoa ve süzme yoğurt kasesi', 'vanilyali-cilekli-kinoa-ve-suzme-yogurt-kasesi-b1c1d2', 'Dengeli porsiyonlu bu kahvaltı, kan şekeri stabilitesi ve kontrollü doygunluk için tasarlandı. Çilek, kinoa ve süzme yoğurt birleşimiyle hafif ama dengeli bir başlangıç sunar.', TRUE, FALSE, FALSE, FALSE, FALSE, NULL, '["Kinoa tabanını uygun bir kapta hazırlayın; gerekiyorsa birkaç dakika önceden sıvı ile yumuşatın.", "Süzme Yoğurt ile çilek parçalarını ayrı bir kapta nazikçe karıştırın.", "Kaseye önce kinoa tabanını, üzerine süzme yoğurt karışımını alın.", "Badem ve seçtiğiniz baharat dokunuşunu üzerine serpin.", "Kıvamı oturduktan sonra soğuk servis edin."]', '["kahvaltı", "kase", "denge", "kompleks karbonhidrat", "fermente", "meyveli"]', 12, 4, 1, 505, 26.00, 50.00, 22.30);
